// components/Navbar.js - Updated for new design
import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

export default function Navbar() {
  const location = useLocation();
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isActive = (path) => {
    return location.pathname === path;
  };

  return (
    <>
      <style>{`
        .navbar-custom {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          z-index: 1000;
          padding: 16px 32px;
          display: flex;
          justify-content: space-between;
          align-items: center;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          backdrop-filter: blur(0px);
          background: transparent;
        }

        .navbar-custom.scrolled {
          padding: 12px 32px;
          background: rgba(9,9,9,0.85);
          backdrop-filter: blur(20px);
          border-bottom: 1px solid rgba(255,255,255,0.04);
        }

        .navbar-brand {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 900;
          font-size: 1.2rem;
          letter-spacing: -0.5px;
          color: #F5F5F5;
          text-decoration: none;
          transition: all 0.3s ease;
        }

        .navbar-brand .highlight {
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .navbar-brand:hover {
          opacity: 0.8;
        }

        .nav-links {
          display: flex;
          align-items: center;
          gap: 8px;
          list-style: none;
          margin: 0;
          padding: 0;
        }

        .nav-links a {
          padding: 8px 18px;
          border-radius: 100px;
          font-family: 'Inter', sans-serif;
          font-size: 0.8rem;
          font-weight: 500;
          color: rgba(255,255,255,0.3);
          text-decoration: none;
          transition: all 0.3s ease;
        }

        .nav-links a:hover {
          color: rgba(255,255,255,0.6);
          background: rgba(255,255,255,0.03);
        }

        .nav-links a.active {
          color: #FF7CC7;
          background: rgba(255,62,165,0.06);
          border: 1px solid rgba(255,62,165,0.06);
        }

        .nav-links .admin-link {
          color: rgba(255,255,255,0.15);
          font-size: 0.7rem;
        }

        .nav-links .admin-link:hover {
          color: rgba(255,255,255,0.3);
          background: transparent;
        }

        .nav-links .admin-link.active {
          color: rgba(255,255,255,0.3);
          background: transparent;
          border: none;
        }

        .mobile-toggle {
          display: none;
          background: none;
          border: 1px solid rgba(255,255,255,0.06);
          border-radius: 8px;
          padding: 8px 12px;
          color: #F5F5F5;
          font-size: 1.2rem;
          cursor: pointer;
          transition: all 0.3s ease;
        }

        .mobile-toggle:hover {
          border-color: rgba(255,255,255,0.1);
        }

        @media (max-width: 768px) {
          .navbar-custom {
            padding: 12px 16px;
          }
          .navbar-custom.scrolled {
            padding: 10px 16px;
          }

          .mobile-toggle {
            display: block;
          }

          .nav-links {
            position: fixed;
            top: 0;
            right: -280px;
            width: 280px;
            height: 100vh;
            flex-direction: column;
            background: rgba(20,20,20,0.98);
            backdrop-filter: blur(20px);
            padding: 80px 24px 24px;
            transition: right 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
            border-left: 1px solid rgba(255,255,255,0.04);
            align-items: stretch;
            gap: 4px;
          }

          .nav-links.open {
            right: 0;
          }

          .nav-links a {
            padding: 14px 18px;
            font-size: 0.9rem;
          }

          .nav-links .admin-link {
            margin-top: 16px;
            border-top: 1px solid rgba(255,255,255,0.04);
            padding-top: 16px;
          }
        }

        @media (max-width: 576px) {
          .navbar-custom {
            padding: 10px 12px;
          }
          .navbar-brand {
            font-size: 1rem;
          }
        }
      `}</style>

      <nav className={`navbar-custom ${scrolled ? 'scrolled' : ''}`}>
        <Link to="/" className="navbar-brand">
          <span className="highlight">H</span>agia
        </Link>

        <button className="mobile-toggle" onClick={() => {
          document.querySelector('.nav-links').classList.toggle('open');
        }}>
          <i className="fas fa-bars"></i>
        </button>

        <ul className="nav-links">
          <Link to="/" className={isActive('/') ? 'active' : ''}>
            Home
          </Link>
          <Link to="/project" className={isActive('/project') ? 'active' : ''}>
            Projects
          </Link>
          <Link to="/admin" className={`admin-link ${isActive('/admin') || isActive('/tambah') || location.pathname.includes('/edit/') ? 'active' : ''}`}>
            <i className="fas fa-lock me-1" style={{ fontSize: '0.6rem' }}></i> Admin
          </Link>
        </ul>
      </nav>
    </>
  );
}
